#include <vector>
#include <queue>
#include <algorithm>
#include <climits>

using namespace std;

struct Edge {
    long long to;
    long long cost;
    long long min_cost;
};

long long solve(std::vector<std::vector<long long>> edges, std::vector<bool> online, long long k) {
    long long n = online.size();
    vector<vector<Edge>> graph(n);
    for (const auto& e : edges) {
        long long u = e[0], v = e[1], cost = e[2];
        if (u == v) continue;
        graph[u].push_back({v, cost, cost});
    }

    priority_queue<pair<long long, pair<long long, long long>>> pq;
    pq.push({0, {0, LLONG_MAX}}); // {total_cost, {current_node, min_edge_cost}}

    long long max_score = -1;

    while (!pq.empty()) {
        auto current = pq.top();
        pq.pop();
        long long current_cost = -current.first;
        long long u = current.second.first;
        long long current_min = current.second.second;

        if (u == n - 1) {
            if (current_cost <= k) {
                max_score = max(max_score, current_min);
            }
            continue;
        }

        for (const auto& edge : graph[u]) {
            long long v = edge.to;
            long long cost = edge.cost;
            if (!online[v] && v != n - 1) continue;

            long long new_total = current_cost + cost;
            if (new_total > k) continue;

            long long new_min = min(current_min, cost);
            pq.push({-new_total, {v, new_min}});
        }
    }

    return max_score;
}

