import java.util.PriorityQueue

fun solve(edges: Array<Array<Long>>, online: Array<Boolean>, k: Long): Long {
    val n = online.size
    val graph = Array(n) { mutableListOf<Triple<Long, Long, Long>>() }
    for (e in edges) {
        val u = e[0]
        val v = e[1]
        val cost = e[2]
        if (u == v) continue
        graph[u.toInt()].add(Triple(v, cost, cost))
    }

    val pq = PriorityQueue<Pair<Long, Pair<Long, Long>>> { a, b ->
        (a.first - b.first).toInt()
    }
    pq.add(0L to (0L to Long.MAX_VALUE))

    var maxScore = -1L

    while (pq.isNotEmpty()) {
        val (currentCost, nodeInfo) = pq.poll()
        val u = nodeInfo.first
        val currentMin = nodeInfo.second

        if (u == n - 1L) {
            if (currentCost <= k) {
                maxScore = maxOf(maxScore, currentMin)
            }
            continue
        }

        for ((v, cost, _) in graph[u.toInt()]) {
            if (!online[v.toInt()] && v != n - 1L) continue

            val newTotal = currentCost + cost
            if (newTotal > k) continue

            val newMin = minOf(currentMin, cost)
            pq.add(newTotal to (v to newMin))
        }
    }

    return maxScore
}
